class Solution {
public:
    vector<vector<int>> largeGroupPositions(string s) {
        vector<vector<int>> result;
        int start = 0;
        for (int end = 0; end < s.length(); end++) {
            if (end == s.length() - 1 || s[end] != s[end + 1]) {
                if (end - start + 1 >= 3) {
                    result.push_back({start, end});
                }
                start = end + 1;
            }
        }
        return result;
    }
};
